#include <string.h>
#include <stdlib.h>

// Check if payload starts with HTTP response and extract code
static inline int em_get_http_response_code(const char *payload, int len) {
    if (payload == NULL || len < 12) return 0;

    // Check for HTTP/1.x response
    if (strncmp(payload, "HTTP/1.", 7) != 0) return 0;

    // Find the space after HTTP/1.x
    const char *p = payload + 8;  // Skip "HTTP/1.x"
    while (*p == ' ' && p < payload + len) p++;

    if (p >= payload + len) return 0;

    // Extract the status code
    return atoi(p);
}

// Check for 401 Unauthorized
static inline int em_check_401_in_payload(const char *payload, int len) {
    if (payload == NULL || len < 12) return 0;
    int code = em_get_http_response_code(payload, len);
    return (code == 401) ? 1 : 0;
}

// Check for 404 Not Found
static inline int em_check_404_in_payload(const char *payload, int len) {
    if (payload == NULL || len < 12) return 0;
    int code = em_get_http_response_code(payload, len);
    return (code == 404) ? 1 : 0;
}

// Check for 422 Unprocessable Entity or 400 Bad Request
static inline int em_check_4xx_invalid_in_payload(const char *payload, int len) {
    if (payload == NULL || len < 12) return 0;
    int code = em_get_http_response_code(payload, len);
    return (code == 422 || code == 400) ? 1 : 0;
}
